class Solution {
    public String arrangeWords(String text) {
        String[] words = text.split(" ");
        int n = words.length;
        // Store the original index of each word
        for (int i = 0; i < n; i++) {
            words[i] = words[i].toLowerCase() + "," + i;
        }
        // Sort the words based on their lengths and original index
        Arrays.sort(words, (a, b) -> {
            int lenA = a.split(",")[0].length();
            int lenB = b.split(",")[0].length();
            if (lenA == lenB) {
                return Integer.parseInt(a.split(",")[1]) - Integer.parseInt(b.split(",")[1]);
            }
            return lenA - lenB;
        });
        // Capitalize the first letter of the first word
        words[0] = words[0].split(",")[0].substring(0, 1).toUpperCase() + words[0].split(",")[0].substring(1) + "," + words[0].split(",")[1];
        StringBuilder sb = new StringBuilder();
        for (String word : words) {
            sb.append(word.split(",")[0]).append(" ");
        }
        return sb.toString().trim();
    }
}
```
